<span class="line">        <span class="token keyword">return</span> <span class="token builtin">float</span><span class="token punctuation">(</span>amount_str<span class="token punctuation">.</span>replace<span class="token punctuation">(</span><span class="token string">&#39;$&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
